import{c as t,Q as a,j as o,m as n}from"./chunks/framework.DpF7k2f3.js";const g=JSON.parse('{"title":"Chapter 7: AI Agent Core Logic","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"en/part2-fundamentals/chapter7.md","filePath":"en/part2-fundamentals/chapter7.md"}'),r={name:"en/part2-fundamentals/chapter7.md"};function i(s,e,l,c,u,p){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="chapter-7-ai-agent-core-logic" tabindex="-1">Chapter 7: AI Agent Core Logic <a class="header-anchor" href="#chapter-7-ai-agent-core-logic" aria-label="Permalink to &quot;Chapter 7: AI Agent Core Logic&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>Congratulations on reaching the final chapter of the Fundamentals section!</p><p>If previous chapters taught you &quot;how to use AI,&quot; then this chapter teaches you &quot;how to let AI work by itself.&quot;</p><p>Let me ask you a question: What is the core difference between LLMs and AI Agents?</p><p>LLMs are passive—you ask, it answers, question and answer, ceiling is low. AI Agents are proactive—you give it a goal, it figures out how to do it, researches on its own, calls tools, verifies results, until the task is complete.</p><p>From &quot;you tell me how to do it&quot; to &quot;you figure it out,&quot; this is a qualitative leap.</p><p>After reading this chapter, you will take away:</p><ul><li><strong>Agent essence</strong>: Why Agents are the future of AI applications</li><li><strong>Agent architecture overview</strong>: The four major components of perception, reasoning, action, and memory</li><li><strong>Tool calling capabilities</strong>: Let AI operate in the real world (including production-grade code)</li><li><strong>Planning and reasoning patterns</strong>: ReAct tracking, LangGraph 2026 practice, Plan-and-Execute</li><li><strong>Multi-Agent collaboration</strong>: Two real usable cases</li><li><strong>Agent reliability engineering</strong>: Six failure patterns, cost control, output validation</li></ul><hr><blockquote><p><strong>Full translation coming soon. You can read the Chinese version in the meantime.</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part2-fundamentals/chapter7.html">阅读中文版</a></p></blockquote>',11)])])}const d=t(r,[["render",i]]);export{g as __pageData,d as default};
